#!/bin/bash
set -e

echo "=============================================="
echo "  VPS Manager Panel v2.3 - Installation"
echo "=============================================="
echo ""

# Admin password: env var, interactive, or auto-generate
if [ -n "$VP_MANAGER_ADMIN_PASS" ]; then
    ADMIN_PASS="$VP_MANAGER_ADMIN_PASS"
    echo "Using provided admin password"
elif [ -t 0 ]; then
    read -sp "Create admin panel password (min 6 chars): " ADMIN_PASS
    echo ""
    if [ -z "$ADMIN_PASS" ] || [ ${#ADMIN_PASS} -lt 6 ]; then
        echo "Password must be at least 6 characters!"
        exit 1
    fi
    read -sp "Confirm admin password: " ADMIN_CONFIRM
    echo ""
    if [ "$ADMIN_PASS" != "$ADMIN_CONFIRM" ]; then
        echo "Passwords do not match!"
        exit 1
    fi
else
    ADMIN_PASS=$(openssl rand -base64 12 2>/dev/null | tr -d '+/=' | head -c 12 || echo "Admin$(date +%s | md5sum | head -c 8)")
    echo "Auto-generated admin password: $ADMIN_PASS"
    echo "  Save this! Change after login at /?page=settings"
fi

echo ""
echo "Installing dependencies..."
apt-get update -qq 2>/dev/null
DEBIAN_FRONTEND=noninteractive apt-get install -y -qq curl unzip nginx mariadb-server phpmyadmin certbot python3-certbot-nginx 2>/dev/null

if ! command -v php8.1 &>/dev/null; then
    apt-get install -y -qq software-properties-common 2>/dev/null || true
    add-apt-repository -y ppa:ondrej/php 2>/dev/null || true
    apt-get update -qq 2>/dev/null
    DEBIAN_FRONTEND=noninteractive apt-get install -y -qq php8.1 php8.1-fpm php8.1-cli php8.1-mysql php8.1-curl php8.1-gd php8.1-mbstring php8.1-xml php8.1-zip php8.1-intl php8.1-bcmath 2>/dev/null
fi

echo "Setting up panel..."
mkdir -p /var/www/manager/backups /var/www/manager/pma

echo "" | base64 -d | gunzip > /var/www/manager/index.php

echo "$ADMIN_PASS" > /var/www/manager/.passwd
chmod 600 /var/www/manager/.passwd
cat > /var/www/manager/.users << USEREOF
[{"user":"admin","pass":"$ADMIN_PASS","role":"admin"}]
USEREOF
chmod 600 /var/www/manager/.users

[ -d /usr/share/phpmyadmin ] && [ ! -L /var/www/manager/pma ] && ln -sf /usr/share/phpmyadmin /var/www/manager/pma
chown -R www-data:www-data /var/www/manager

echo "Configuring Nginx on port 8080..."
cat > /etc/nginx/sites-available/vps-manager << 'NGX'
server {
    listen 8080;
    server_name _;
    root /var/www/manager;
    index index.php index.html;
    location / { try_files $uri $uri/ /index.php?$query_string; }
    location ~ \.php$ { include snippets/fastcgi-php.conf; fastcgi_pass unix:/var/run/php/php8.1-fpm.sock; }
    location ~ /\. { deny all; }
    client_max_body_size 100M;
}
NGX
rm -f /etc/nginx/sites-enabled/default
ln -sf /etc/nginx/sites-available/vps-manager /etc/nginx/sites-enabled/

# Start services
systemctl enable --now php8.1-fpm 2>/dev/null || true
nginx -t && systemctl restart nginx

# Clean old pm2/systemd approaches
pm2 stop vps-manager 2>/dev/null; pm2 delete vps-manager 2>/dev/null; true
systemctl stop vps-manager 2>/dev/null; systemctl disable vps-manager 2>/dev/null; true
rm -f /etc/systemd/system/vps-manager.service
systemctl daemon-reload 2>/dev/null || true

sleep 2

IP=$(curl -s4 ifconfig.me 2>/dev/null || hostname -I | awk '{print $1}')
echo ""
echo "=============================================="
echo "  INSTALLATION COMPLETE!"
echo "=============================================="
echo ""
echo "  Panel URL:  http://$IP:8080"
echo "  Username:   admin"
echo "  Password:   $ADMIN_PASS"
echo ""
echo "  phpMyAdmin: http://$IP:8080/pma"
echo "=============================================="
